/**
 * Notification log model — represents a historical record of a sent notification.
 *
 * Every notification processed by the NotificationService (whether delivered,
 * failed, or suppressed) is recorded as a NotificationLog entry for auditing
 * and querying.
 */

import type { NotificationChannel, NotificationType, NotificationPriority } from './notification.js';

/**
 * Delivery status of a logged notification.
 */
export type DeliveryStatus = 'delivered' | 'failed' | 'suppressed';

/**
 * A persistent record of a notification that was processed.
 */
export interface NotificationLog {
  /** Unique log entry ID */
  id: string;
  /** The original notification ID */
  notificationId: string;
  /** Recipient identifier (email, user ID, etc.) */
  recipient: string;
  /** Delivery channel used */
  channel: NotificationChannel;
  /** The type of notification */
  type: NotificationType;
  /** Priority level */
  priority: NotificationPriority;
  /** Subject line */
  subject: string;
  /** Delivery status */
  status: DeliveryStatus;
  /** Error message if delivery failed or was suppressed */
  error?: string;
  /** When the notification was created */
  createdAt: Date;
  /** When delivery was attempted */
  deliveredAt?: Date;
}

/**
 * Filters for querying notification history.
 */
export interface NotificationLogQuery {
  /** Filter by recipient */
  recipient?: string;
  /** Filter by notification channel */
  channel?: NotificationChannel;
  /** Filter by notification type */
  type?: NotificationType;
  /** Filter by delivery status */
  status?: DeliveryStatus;
  /** Filter notifications created on or after this date */
  startDate?: Date;
  /** Filter notifications created on or before this date */
  endDate?: Date;
}

/**
 * Repository for NotificationLog data access.
 *
 * Extends BaseRepository with notification-log-specific query methods.
 */

import type { DatabaseRecord } from '../utils/database.js';
import type { Database } from '../utils/database.js';
import type { NotificationLog, DeliveryStatus } from '../models/notification-log.js';
import type { NotificationChannel, NotificationType, NotificationPriority } from '../models/notification.js';
import { BaseRepository } from './base.repository.js';

export class NotificationLogRepository extends BaseRepository<NotificationLog> {
  constructor(db: Database) {
    super(db, 'notification_logs');
  }

  protected toDomain(record: DatabaseRecord): NotificationLog {
    return {
      id: record['id'] as string,
      notificationId: record['notificationId'] as string,
      recipient: record['recipient'] as string,
      channel: record['channel'] as NotificationChannel,
      type: record['type'] as NotificationType,
      priority: record['priority'] as NotificationPriority,
      subject: record['subject'] as string,
      status: record['status'] as DeliveryStatus,
      error: record['error'] as string | undefined,
      createdAt: new Date(record['createdAt'] as string),
      deliveredAt: record['deliveredAt'] ? new Date(record['deliveredAt'] as string) : undefined,
    };
  }

  protected toRecord(entity: NotificationLog): DatabaseRecord {
    return {
      id: entity.id,
      notificationId: entity.notificationId,
      recipient: entity.recipient,
      channel: entity.channel,
      type: entity.type,
      priority: entity.priority,
      subject: entity.subject,
      status: entity.status,
      error: entity.error,
      createdAt: entity.createdAt.toISOString(),
      deliveredAt: entity.deliveredAt?.toISOString(),
    };
  }

  /**
   * Find all log entries for a specific recipient.
   */
  findByRecipient(recipient: string): NotificationLog[] {
    return this.findAll((log) => log.recipient === recipient);
  }

  /**
   * Find all log entries for a specific notification type.
   */
  findByType(type: NotificationType): NotificationLog[] {
    return this.findAll((log) => log.type === type);
  }

  /**
   * Find all log entries for a specific channel.
   */
  findByChannel(channel: NotificationChannel): NotificationLog[] {
    return this.findAll((log) => log.channel === channel);
  }

  /**
   * Find all log entries with a specific delivery status.
   */
  findByStatus(status: DeliveryStatus): NotificationLog[] {
    return this.findAll((log) => log.status === status);
  }
}

/**
 * Notification history service — logs and queries notification history.
 *
 * Integrates with NotificationService via setter injection. Every notification
 * processed by NotificationService is logged here for auditing and querying.
 *
 * Depends on:
 * - NotificationLogRepository for persistence
 * - paginate() utility for paginated queries
 */

import type { Notification } from '../models/notification.js';
import type { NotificationLog, NotificationLogQuery, DeliveryStatus } from '../models/notification-log.js';
import type { NotificationLogRepository } from '../repositories/notification-log.repository.js';
import { paginate } from '../utils/pagination.js';
import type { PaginationResult } from '../utils/pagination.js';
import { Logger } from '../utils/logger.js';

let nextLogId = 1;

function generateLogId(): string {
  return `nlog-${String(nextLogId++).padStart(4, '0')}`;
}

export function resetNotificationLogIdCounter(): void {
  nextLogId = 1;
}

/**
 * Derive delivery status from a Notification record.
 */
function deriveStatus(notification: Notification): DeliveryStatus {
  if (notification.delivered) {
    return 'delivered';
  }
  if (notification.error === 'Suppressed by user preferences') {
    return 'suppressed';
  }
  return 'failed';
}

export class NotificationHistoryService {
  private logger = new Logger('NotificationHistoryService');

  constructor(private repository: NotificationLogRepository) {}

  /**
   * Log a notification that was processed by the NotificationService.
   * Called after each sendNotification() completes.
   */
  logNotification(notification: Notification): NotificationLog {
    const logEntry: NotificationLog = {
      id: generateLogId(),
      notificationId: notification.id,
      recipient: notification.recipient,
      channel: notification.channel,
      type: notification.type,
      priority: notification.priority,
      subject: notification.subject,
      status: deriveStatus(notification),
      error: notification.error,
      createdAt: notification.createdAt,
      deliveredAt: notification.deliveredAt,
    };

    this.repository.save(logEntry);
    this.logger.info(
      `Logged notification ${notification.id}: status=${logEntry.status}, recipient=${logEntry.recipient}`,
    );
    return logEntry;
  }

  /**
   * Query notification history with optional filters.
   */
  queryHistory(query: NotificationLogQuery = {}): NotificationLog[] {
    return this.repository.findAll((log) => {
      if (query.recipient && log.recipient !== query.recipient) return false;
      if (query.channel && log.channel !== query.channel) return false;
      if (query.type && log.type !== query.type) return false;
      if (query.status && log.status !== query.status) return false;
      if (query.startDate && log.createdAt < query.startDate) return false;
      if (query.endDate && log.createdAt > query.endDate) return false;
      return true;
    });
  }

  /**
   * Query notification history with pagination.
   */
  queryHistoryPaginated(
    query: NotificationLogQuery = {},
    page: number = 1,
    pageSize: number = 10,
  ): PaginationResult<NotificationLog> {
    const results = this.queryHistory(query);
    return paginate(results, page, pageSize);
  }

  /**
   * Get all log entries for a specific recipient.
   */
  getHistoryForRecipient(recipient: string): NotificationLog[] {
    return this.repository.findByRecipient(recipient);
  }

  /**
   * Get the total count of logged notifications.
   */
  getLogCount(): number {
    return this.repository.count();
  }

  /**
   * Get a single log entry by its ID.
   */
  getLogEntry(id: string): NotificationLog | undefined {
    return this.repository.findById(id);
  }
}

