import { describe, it, expect, beforeEach } from 'vitest';
import { Database } from '../../src/utils/database.js';
import { NotificationLogRepository } from '../../src/repositories/notification-log.repository.js';
import {
  NotificationHistoryService,
  resetNotificationLogIdCounter,
} from '../../src/services/notification-history.service.js';
import { EventBus } from '../../src/events/event-bus.js';
import {
  NotificationService,
  resetNotificationIdCounter,
} from '../../src/services/notification.service.js';
import type { Notification } from '../../src/models/notification.js';

function makeNotification(overrides: Partial<Notification> = {}): Notification {
  return {
    id: 'notif-0001',
    type: 'order-confirmation',
    channel: 'email',
    recipient: 'alice@example.com',
    subject: 'Order Confirmation',
    body: 'Your order has been placed.',
    priority: 'normal',
    delivered: true,
    createdAt: new Date('2026-01-15T10:00:00Z'),
    deliveredAt: new Date('2026-01-15T10:00:01Z'),
    ...overrides,
  };
}

describe('NotificationHistoryService', () => {
  let db: Database;
  let repository: NotificationLogRepository;
  let service: NotificationHistoryService;

  beforeEach(() => {
    db = new Database();
    repository = new NotificationLogRepository(db);
    service = new NotificationHistoryService(repository);
    resetNotificationLogIdCounter();
  });

  describe('logNotification', () => {
    it('should log a delivered notification', () => {
      const notification = makeNotification();
      const log = service.logNotification(notification);

      expect(log.id).toBe('nlog-0001');
      expect(log.notificationId).toBe('notif-0001');
      expect(log.recipient).toBe('alice@example.com');
      expect(log.channel).toBe('email');
      expect(log.type).toBe('order-confirmation');
      expect(log.priority).toBe('normal');
      expect(log.subject).toBe('Order Confirmation');
      expect(log.status).toBe('delivered');
      expect(log.error).toBeUndefined();
      expect(log.deliveredAt).toEqual(new Date('2026-01-15T10:00:01Z'));
    });

    it('should log a failed notification', () => {
      const notification = makeNotification({
        delivered: false,
        error: 'No adapter registered for channel: email',
        deliveredAt: undefined,
      });
      const log = service.logNotification(notification);

      expect(log.status).toBe('failed');
      expect(log.error).toBe('No adapter registered for channel: email');
    });

    it('should log a suppressed notification', () => {
      const notification = makeNotification({
        delivered: false,
        error: 'Suppressed by user preferences',
        deliveredAt: undefined,
      });
      const log = service.logNotification(notification);

      expect(log.status).toBe('suppressed');
      expect(log.error).toBe('Suppressed by user preferences');
    });

    it('should persist log entries to the repository', () => {
      service.logNotification(makeNotification());
      service.logNotification(makeNotification({ id: 'notif-0002', recipient: 'bob@example.com' }));

      expect(service.getLogCount()).toBe(2);
    });

    it('should generate sequential log IDs', () => {
      const log1 = service.logNotification(makeNotification({ id: 'notif-0001' }));
      const log2 = service.logNotification(makeNotification({ id: 'notif-0002' }));

      expect(log1.id).toBe('nlog-0001');
      expect(log2.id).toBe('nlog-0002');
    });
  });

  describe('queryHistory', () => {
    beforeEach(() => {
      service.logNotification(makeNotification({
        id: 'notif-0001',
        recipient: 'alice@example.com',
        channel: 'email',
        type: 'order-confirmation',
        delivered: true,
        createdAt: new Date('2026-01-10T10:00:00Z'),
      }));
      service.logNotification(makeNotification({
        id: 'notif-0002',
        recipient: 'bob@example.com',
        channel: 'webhook',
        type: 'order-status-update',
        delivered: true,
        createdAt: new Date('2026-01-15T10:00:00Z'),
      }));
      service.logNotification(makeNotification({
        id: 'notif-0003',
        recipient: 'alice@example.com',
        channel: 'email',
        type: 'welcome',
        delivered: false,
        error: 'Suppressed by user preferences',
        createdAt: new Date('2026-01-20T10:00:00Z'),
      }));
      service.logNotification(makeNotification({
        id: 'notif-0004',
        recipient: 'alice@example.com',
        channel: 'email',
        type: 'order-confirmation',
        delivered: false,
        error: 'Transport error',
        createdAt: new Date('2026-01-25T10:00:00Z'),
      }));
    });

    it('should return all logs when no filters are applied', () => {
      const results = service.queryHistory();
      expect(results).toHaveLength(4);
    });

    it('should filter by recipient', () => {
      const results = service.queryHistory({ recipient: 'alice@example.com' });
      expect(results).toHaveLength(3);
      expect(results.every((r) => r.recipient === 'alice@example.com')).toBe(true);
    });

    it('should filter by channel', () => {
      const results = service.queryHistory({ channel: 'webhook' });
      expect(results).toHaveLength(1);
      expect(results[0].recipient).toBe('bob@example.com');
    });

    it('should filter by type', () => {
      const results = service.queryHistory({ type: 'order-confirmation' });
      expect(results).toHaveLength(2);
    });

    it('should filter by status', () => {
      const delivered = service.queryHistory({ status: 'delivered' });
      expect(delivered).toHaveLength(2);

      const suppressed = service.queryHistory({ status: 'suppressed' });
      expect(suppressed).toHaveLength(1);

      const failed = service.queryHistory({ status: 'failed' });
      expect(failed).toHaveLength(1);
    });

    it('should filter by date range', () => {
      const results = service.queryHistory({
        startDate: new Date('2026-01-12T00:00:00Z'),
        endDate: new Date('2026-01-22T00:00:00Z'),
      });
      expect(results).toHaveLength(2);
    });

    it('should filter by startDate only', () => {
      const results = service.queryHistory({
        startDate: new Date('2026-01-20T00:00:00Z'),
      });
      expect(results).toHaveLength(2);
    });

    it('should filter by endDate only', () => {
      const results = service.queryHistory({
        endDate: new Date('2026-01-15T10:00:00Z'),
      });
      expect(results).toHaveLength(2);
    });

    it('should combine multiple filters', () => {
      const results = service.queryHistory({
        recipient: 'alice@example.com',
        type: 'order-confirmation',
        status: 'delivered',
      });
      expect(results).toHaveLength(1);
      expect(results[0].notificationId).toBe('notif-0001');
    });

    it('should return empty array when no matches found', () => {
      const results = service.queryHistory({ recipient: 'unknown@example.com' });
      expect(results).toHaveLength(0);
    });
  });

  describe('queryHistoryPaginated', () => {
    beforeEach(() => {
      for (let i = 1; i <= 25; i++) {
        service.logNotification(makeNotification({
          id: `notif-${String(i).padStart(4, '0')}`,
          recipient: 'alice@example.com',
          createdAt: new Date(`2026-01-${String(i).padStart(2, '0')}T10:00:00Z`),
        }));
      }
    });

    it('should return first page with correct metadata', () => {
      const result = service.queryHistoryPaginated({}, 1, 10);
      expect(result.items).toHaveLength(10);
      expect(result.page).toBe(1);
      expect(result.pageSize).toBe(10);
      expect(result.totalItems).toBe(25);
      expect(result.totalPages).toBe(3);
      expect(result.hasNext).toBe(true);
      expect(result.hasPrevious).toBe(false);
    });

    it('should return last page with remaining items', () => {
      const result = service.queryHistoryPaginated({}, 3, 10);
      expect(result.items).toHaveLength(5);
      expect(result.hasNext).toBe(false);
      expect(result.hasPrevious).toBe(true);
    });

    it('should apply filters before paginating', () => {
      // Log some for a different recipient
      service.logNotification(makeNotification({
        id: 'notif-extra',
        recipient: 'bob@example.com',
      }));

      const result = service.queryHistoryPaginated(
        { recipient: 'alice@example.com' },
        1,
        10,
      );
      expect(result.totalItems).toBe(25);
      expect(result.items).toHaveLength(10);
    });
  });

  describe('getHistoryForRecipient', () => {
    it('should return all logs for a specific recipient', () => {
      service.logNotification(makeNotification({ id: 'notif-0001', recipient: 'alice@example.com' }));
      service.logNotification(makeNotification({ id: 'notif-0002', recipient: 'bob@example.com' }));
      service.logNotification(makeNotification({ id: 'notif-0003', recipient: 'alice@example.com' }));

      const results = service.getHistoryForRecipient('alice@example.com');
      expect(results).toHaveLength(2);
    });

    it('should return empty array for unknown recipient', () => {
      const results = service.getHistoryForRecipient('nobody@example.com');
      expect(results).toHaveLength(0);
    });
  });

  describe('getLogEntry', () => {
    it('should retrieve a specific log entry by ID', () => {
      service.logNotification(makeNotification());
      const entry = service.getLogEntry('nlog-0001');

      expect(entry).toBeDefined();
      expect(entry!.notificationId).toBe('notif-0001');
    });

    it('should return undefined for non-existent ID', () => {
      const entry = service.getLogEntry('nlog-9999');
      expect(entry).toBeUndefined();
    });
  });
});

describe('NotificationService with history tracking', () => {
  let eventBus: EventBus;
  let notificationService: NotificationService;
  let historyService: NotificationHistoryService;
  let db: Database;

  beforeEach(() => {
    eventBus = new EventBus();
    notificationService = new NotificationService(eventBus);
    db = new Database();
    const repository = new NotificationLogRepository(db);
    historyService = new NotificationHistoryService(repository);
    notificationService.setHistoryService(historyService);
    resetNotificationIdCounter();
    resetNotificationLogIdCounter();
  });

  it('should log delivered notifications to history', async () => {
    const mockAdapter = {
      channel: 'email' as const,
      send: async (payload: any) => ({
        success: true,
        notificationId: payload.id,
        channel: 'email' as const,
        deliveredAt: new Date('2026-01-15T10:00:01Z'),
      }),
    };
    notificationService.registerAdapter(mockAdapter);

    await notificationService.sendNotification({
      type: 'order-confirmation',
      channel: 'email',
      recipient: 'alice@example.com',
      subject: 'Test',
      body: 'Test body',
      priority: 'normal',
    });

    expect(historyService.getLogCount()).toBe(1);
    const logs = historyService.getHistoryForRecipient('alice@example.com');
    expect(logs).toHaveLength(1);
    expect(logs[0].status).toBe('delivered');
    expect(logs[0].channel).toBe('email');
  });

  it('should log failed notifications to history', async () => {
    // No adapter registered — will fail
    await notificationService.sendNotification({
      type: 'order-confirmation',
      channel: 'email',
      recipient: 'alice@example.com',
      subject: 'Test',
      body: 'Test body',
      priority: 'normal',
    });

    expect(historyService.getLogCount()).toBe(1);
    const logs = historyService.queryHistory({ status: 'failed' });
    expect(logs).toHaveLength(1);
    expect(logs[0].error).toContain('No adapter registered');
  });

  it('should log suppressed notifications to history', async () => {
    // Set up preferences service to suppress
    const prefDb = new Database();
    const { PreferencesRepository } = await import('../../src/repositories/preferences.repository.js');
    const { PreferencesService } = await import('../../src/services/preferences.service.js');
    const prefRepo = new PreferencesRepository(prefDb);
    const preferencesService = new PreferencesService(prefRepo);
    notificationService.setPreferencesService(preferencesService);

    preferencesService.updatePreferences('alice@example.com', {
      email: { enabled: false },
    });

    await notificationService.sendNotification({
      type: 'order-confirmation',
      channel: 'email',
      recipient: 'alice@example.com',
      subject: 'Test',
      body: 'Test body',
      priority: 'normal',
    });

    expect(historyService.getLogCount()).toBe(1);
    const logs = historyService.queryHistory({ status: 'suppressed' });
    expect(logs).toHaveLength(1);
  });

  it('should work without history service set (backwards compatible)', async () => {
    const plainService = new NotificationService(eventBus);
    // No setHistoryService called

    const notification = await plainService.sendNotification({
      type: 'order-confirmation',
      channel: 'email',
      recipient: 'alice@example.com',
      subject: 'Test',
      body: 'Test body',
      priority: 'normal',
    });

    // Should complete without error
    expect(notification.id).toBeDefined();
    expect(historyService.getLogCount()).toBe(0);
  });

  it('should log multiple notifications and support querying', async () => {
    await notificationService.sendNotification({
      type: 'order-confirmation',
      channel: 'email',
      recipient: 'alice@example.com',
      subject: 'Order 1',
      body: 'Body 1',
      priority: 'normal',
    });

    await notificationService.sendNotification({
      type: 'order-status-update',
      channel: 'email',
      recipient: 'bob@example.com',
      subject: 'Order 2',
      body: 'Body 2',
      priority: 'high',
    });

    await notificationService.sendNotification({
      type: 'order-confirmation',
      channel: 'email',
      recipient: 'alice@example.com',
      subject: 'Order 3',
      body: 'Body 3',
      priority: 'normal',
    });

    expect(historyService.getLogCount()).toBe(3);

    const aliceLogs = historyService.queryHistory({ recipient: 'alice@example.com' });
    expect(aliceLogs).toHaveLength(2);

    const confirmationLogs = historyService.queryHistory({ type: 'order-confirmation' });
    expect(confirmationLogs).toHaveLength(2);
  });
});

