+/**
+ * Notification history service — logs and queries notification history.
+ *
+ * Integrates with NotificationService via setter injection. Every notification
+ * processed by NotificationService is logged here for auditing and querying.
+ *
+ * Depends on:
+ * - NotificationLogRepository for persistence
+ * - paginate() utility for paginated queries
+ */
+
+import type { Notification } from '../models/notification.js';
+import type { NotificationLog, NotificationLogQuery, DeliveryStatus } from '../models/notification-log.js';
+import type { NotificationLogRepository } from '../repositories/notification-log.repository.js';
+import { paginate } from '../utils/pagination.js';
+import type { PaginationResult } from '../utils/pagination.js';
+import { Logger } from '../utils/logger.js';
+
+let nextLogId = 1;
+
+function generateLogId(): string {
+  return `nlog-${String(nextLogId++).padStart(4, '0')}`;
+}
+
+export function resetNotificationLogIdCounter(): void {
+  nextLogId = 1;
+}
+
+/**
+ * Derive delivery status from a Notification record.
+ */
+function deriveStatus(notification: Notification): DeliveryStatus {
+  if (notification.delivered) {
+    return 'delivered';
+  }
+  if (notification.error === 'Suppressed by user preferences') {
+    return 'suppressed';
+  }
+  return 'failed';
+}
+
+export class NotificationHistoryService {
+  private logger = new Logger('NotificationHistoryService');
+
+  constructor(private repository: NotificationLogRepository) {}
+
+  /**
+   * Log a notification that was processed by the NotificationService.
+   * Called after each sendNotification() completes.
+   */
+  logNotification(notification: Notification): NotificationLog {
+    const logEntry: NotificationLog = {
+      id: generateLogId(),
+      notificationId: notification.id,
+      recipient: notification.recipient,
+      channel: notification.channel,
+      type: notification.type,
+      priority: notification.priority,
+      subject: notification.subject,
+      status: deriveStatus(notification),
+      error: notification.error,
+      createdAt: notification.createdAt,
+      deliveredAt: notification.deliveredAt,
+    };
+
+    this.repository.save(logEntry);
+    this.logger.info(
+      `Logged notification ${notification.id}: status=${logEntry.status}, recipient=${logEntry.recipient}`,
+    );
+    return logEntry;
+  }
+
+  /**
+   * Query notification history with optional filters.
+   */
+  queryHistory(query: NotificationLogQuery = {}): NotificationLog[] {
+    return this.repository.findAll((log) => {
+      if (query.recipient && log.recipient !== query.recipient) return false;
+      if (query.channel && log.channel !== query.channel) return false;
+      if (query.type && log.type !== query.type) return false;
+      if (query.status && log.status !== query.status) return false;
+      if (query.startDate && log.createdAt < query.startDate) return false;
+      if (query.endDate && log.createdAt > query.endDate) return false;
+      return true;
+    });
+  }
+
+  /**
+   * Query notification history with pagination.
+   */
+  queryHistoryPaginated(
+    query: NotificationLogQuery = {},
+    page: number = 1,
+    pageSize: number = 10,
+  ): PaginationResult<NotificationLog> {
+    const results = this.queryHistory(query);
+    return paginate(results, page, pageSize);
+  }
+
+  /**
+   * Get all log entries for a specific recipient.
+   */
+  getHistoryForRecipient(recipient: string): NotificationLog[] {
+    return this.repository.findByRecipient(recipient);
+  }
+
+  /**
+   * Get the total count of logged notifications.
+   */
+  getLogCount(): number {
+    return this.repository.count();
+  }
+
+  /**
+   * Get a single log entry by its ID.
+   */
+  getLogEntry(id: string): NotificationLog | undefined {
+    return this.repository.findById(id);
+  }
+}

